import React from 'react';
import { motion } from 'framer-motion';
import { useTheme } from '../contexts/ThemeContext';
import './Experience.css';

const Experience = () => {
  const { isDarkMode } = useTheme();

  const experiences = [
    {
      title: "Senior Cloud Engineer",
      company: "Tech Solutions Inc.",
      period: "2022 - Present",
      description: "Led cloud migration projects and implemented DevOps practices for enterprise clients.",
      achievements: [
        "Reduced infrastructure costs by 40% through optimization",
        "Implemented CI/CD pipelines for 15+ applications",
        "Managed multi-region AWS deployments"
      ]
    },
    {
      title: "Cloud Developer",
      company: "Digital Innovations",
      period: "2020 - 2022",
      description: "Developed serverless applications and automated cloud infrastructure.",
      achievements: [
        "Built 20+ Lambda functions for data processing",
        "Automated deployment processes using Terraform",
        "Implemented monitoring and alerting systems"
      ]
    },
    {
      title: "DevOps Engineer",
      company: "StartupTech",
      period: "2019 - 2020",
      description: "Established DevOps culture and implemented cloud-first architecture.",
      achievements: [
        "Set up complete CI/CD infrastructure from scratch",
        "Reduced deployment time from hours to minutes",
        "Implemented infrastructure as code practices"
      ]
    }
  ];

  return (
    <section id="experience" className={`experience-section ${isDarkMode ? 'dark' : ''}`}>
      <div className="container">
        <motion.h2 
          className="section-title"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          Professional Experience
        </motion.h2>
        <div className="experience-timeline">
          {experiences.map((exp, index) => (
            <motion.div 
              key={index}
              className="experience-item"
              initial={{ opacity: 0, x: index % 2 === 0 ? -50 : 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ delay: index * 0.2, duration: 0.6 }}
              viewport={{ once: true }}
            >
              <div className="experience-content">
                <div className="experience-header">
                  <h3>{exp.title}</h3>
                  <span className="company">{exp.company}</span>
                  <span className="period">{exp.period}</span>
                </div>
                <p className="description">{exp.description}</p>
                <ul className="achievements">
                  {exp.achievements.map((achievement, i) => (
                    <li key={i}>{achievement}</li>
                  ))}
                </ul>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
